// donnees.js — Données partagées La Rochelle électorale
// Ce fichier est importé par LRVcarte.html, LRVanalyse.html, index.html, editeur_candidats.html
// `bd.c[cname]` stocke des VOIX (entiers) ; les pourcentages sont calculés à la volée.

// Date de dernière mise à jour des données (format ISO YYYY-MM-DD).
// À actualiser à chaque rafraîchissement notable du jeu de données.
const LAST_UPDATE = '2026-04-30';

// Formatage convivial : '2026-04-30' → 'avril 2026'
function formatLastUpdate(iso) {
  if (!iso) return '';
  const months = ['janvier','février','mars','avril','mai','juin','juillet','août','septembre','octobre','novembre','décembre'];
  const m = String(iso).match(/^(\d{4})-(\d{2})/);
  if (!m) return iso;
  return months[parseInt(m[2]) - 1] + ' ' + m[1];
}

